{
  "question": "PLG tier alongside consulting",
  "hypotheses": [
    {
      "id": "H1",
      "label": "Complementary Growth Engine",
      "description": "A self-serve PLG tier acts as a high-volume top-of-funnel that naturally upsells into higher-margin consulting engagements, accelerating overall revenue growth and reducing customer acquisition costs.",
      "inconsistency_count": 2,
      "eliminated": false
    },
    {
      "id": "H2",
      "label": "Brand and Margin Dilution Risk",
      "description": "Offering a low-cost PLG tier alongside premium consulting cannibalizes consulting revenue, confuses market positioning, and erodes the perceived value of expert-led services among key accounts.",
      "inconsistency_count": 5,
      "eliminated": false
    },
    {
      "id": "H3",
      "label": "Operationally Incompatible Models",
      "description": "The organizational capabilities, culture, and unit economics required to run a scalable PLG product are fundamentally at odds with a consulting practice, leading to internal resource conflicts and underperformance in both motions.",
      "inconsistency_count": 0,
      "eliminated": false
    },
    {
      "id": "H4",
      "label": "Margin-accretive funnel",
      "description": "A low-touch PLG tier serves as a high-margin, self-serve revenue stream that also acts as a qualified lead funnel into high-ACV consulting engagements, improving blended margins and reducing customer acquisition cost.",
      "inconsistency_count": 2,
      "eliminated": false
    },
    {
      "id": "H5",
      "label": "Margin-dilutive distraction",
      "description": "The PLG tier demands significant upfront engineering and support investment while generating low ARPU, diluting overall gross margins and diverting capital and management attention away from the high-margin consulting business.",
      "inconsistency_count": 1,
      "eliminated": false
    },
    {
      "id": "H6",
      "label": "Cash flow hedge with cannibalization risk",
      "description": "The PLG tier provides predictable recurring revenue that smooths the lumpy cash flow profile of consulting, but risks cannibalizing consulting deals as prospects self-serve instead of engaging in higher-value professional services contracts.",
      "inconsistency_count": 2,
      "eliminated": false
    },
    {
      "id": "H7",
      "label": "Shared platform, divergent complexity",
      "description": "A single codebase can serve both the self-serve PLG tier and the consulting-customized tier by using feature flags and a modular architecture, but the diverging requirements will accumulate significant tech debt and slow both product lines over time.",
      "inconsistency_count": 0,
      "eliminated": false
    },
    {
      "id": "H8",
      "label": "PLG accelerates consulting pipeline",
      "description": "A well-instrumented PLG tier acts as a low-friction technical proof-of-concept that generates qualified consulting leads, and the telemetry from self-serve usage directly informs which enterprise features to prioritize in the consulting engagement stack.",
      "inconsistency_count": 2,
      "eliminated": false
    },
    {
      "id": "H9",
      "label": "Separate stacks required for security and scale",
      "description": "The security, compliance, and data-isolation requirements of consulting clients are fundamentally incompatible with the multi-tenant, rapid-iteration PLG infrastructure, necessitating two largely independent technical stacks and doubling engineering operational burden.",
      "inconsistency_count": 1,
      "eliminated": false
    },
    {
      "id": "H10",
      "label": "Brand dilution and price anchoring risk",
      "description": "Offering a low-cost or free PLG tier alongside premium consulting creates a damaging price anchor that undermines the perceived value of consulting services, confuses market positioning, and attracts a non-ICP audience that drains resources.",
      "inconsistency_count": 5,
      "eliminated": false
    },
    {
      "id": "H11",
      "label": "Parallel segments, minimal crossover",
      "description": "The PLG tier and consulting practice serve fundamentally different buyer personas and purchase motivations, resulting in two essentially independent business lines that compete for internal resources and messaging clarity without meaningful cross-sell synergy.",
      "inconsistency_count": 7,
      "eliminated": true
    }
  ],
  "evidence": [
    {
      "id": "E1",
      "description": "Observed conversion rate and average deal size of PLG users who upgrade into paid consulting engagements, compared against the baseline ACV and win-rate of consulting deals sourced through traditional sales channels \u2014 directly discriminates funnel synergy (H1, H4, H8) from minimal crossover (H11) and cannibalization (H6, H10).",
      "diagnostic_score": 0.2727272727272727
    },
    {
      "id": "E2",
      "description": "Consulting pipeline win-rate and average ACV trend data before versus after the introduction of a PLG tier (or a comparable company's public data), specifically whether enterprise buyers reference the self-serve price as an anchor during negotiations \u2014 differentiates price-anchoring/brand-dilution risk (H2, H10) from complementary positioning (H1, H4).",
      "diagnostic_score": 0.18181818181818182
    },
    {
      "id": "E3",
      "description": "ICP overlap analysis showing the percentage of PLG sign-ups whose firmographic and behavioral profiles match the ideal consulting client persona, versus those who are fundamentally different buyer types (e.g., individual developers vs. enterprise transformation sponsors) \u2014 directly tests H11 (parallel segments, minimal crossover) against H1/H8 (funnel synergy).",
      "diagnostic_score": 0.2727272727272727
    },
    {
      "id": "E4",
      "description": "Engineering velocity and incident-rate metrics for teams operating a shared codebase serving both self-serve and consulting-customized deployments, including measured tech-debt accumulation, security/compliance audit pass rates, and feature release cadence per product line \u2014 discriminates shared-platform viability (H7) from operational incompatibility (H3, H9).",
      "diagnostic_score": 0.18181818181818182
    },
    {
      "id": "E5",
      "description": "Blended gross margin, fully-loaded customer acquisition cost, and cash-flow volatility trajectory over 4+ quarters post-PLG launch, segmented by PLG-only, consulting-only, and cross-sell cohorts \u2014 directly differentiates margin-accretive funnel (H4) from margin-dilutive distraction (H5) and tests the cash-flow smoothing claim (H6).",
      "diagnostic_score": 0.18181818181818182
    },
    {
      "id": "E6",
      "description": "Observed PLG-to-consulting conversion rate: the percentage of self-serve PLG accounts that convert into paid consulting engagements within 12 months, including the average time-to-convert and the ACV of those converted deals versus deals sourced through traditional sales.",
      "diagnostic_score": 0.2727272727272727
    },
    {
      "id": "E7",
      "description": "Fully-loaded gross margin by motion: PLG tier gross margin (inclusive of infrastructure, support, and allocated engineering maintenance costs) compared to consulting engagement gross margin, tracked quarterly over the first 24 months post-launch to reveal trajectory.",
      "diagnostic_score": 0.18181818181818182
    },
    {
      "id": "E8",
      "description": "Consulting ACV and win-rate trend post-PLG launch: change in average contract value and close rates for consulting deals after the PLG tier becomes publicly available, segmented by whether the prospect had prior PLG usage, to isolate price-anchoring and cannibalization effects.",
      "diagnostic_score": 0.18181818181818182
    },
    {
      "id": "E9",
      "description": "Incremental engineering and operational cost to support both motions: the actual (or projected) additional headcount, infrastructure spend, and shared-codebase maintenance burden required to run PLG alongside consulting, including observed tech-debt accrual rate and incident cross-contamination frequency.",
      "diagnostic_score": 0.2727272727272727
    },
    {
      "id": "E10",
      "description": "Buyer persona overlap analysis: proportion of PLG signups that match the consulting ideal customer profile (by firmographic, role, and budget authority) versus those that are fundamentally different segments, along with quarterly cash-flow variance reduction attributable to recurring PLG revenue.",
      "diagnostic_score": 0.18181818181818182
    },
    {
      "id": "E11",
      "description": "Observed PLG-to-consulting conversion rate and average time-to-convert: the percentage of self-serve PLG accounts that initiate or close a consulting engagement within 12 months, compared to consulting leads sourced through traditional channels. Directly differentiates H1/H4/H8 (meaningful funnel) from H11 (minimal crossover) and H6 (cannibalization dominates).",
      "diagnostic_score": 0.2727272727272727
    },
    {
      "id": "E12",
      "description": "Gap analysis of consulting-client security, compliance, and data-isolation requirements (e.g., SOC 2 Type II, single-tenant deployment, RBAC, audit logging) versus the current multi-tenant PLG architecture's capabilities. Differentiates H7 (shared platform feasible with feature flags) from H9 (fundamentally incompatible stacks requiring separate infrastructure).",
      "diagnostic_score": 0.18181818181818182
    },
    {
      "id": "E13",
      "description": "Engineering velocity and tech-debt trajectory metrics (deploy frequency, cycle time, defect escape rate, percentage of sprints spent on cross-tier compatibility work) measured before and after supporting both PLG and consulting-customized tiers on a shared codebase. Differentiates H7 (manageable divergence) from H3/H5 (resource conflicts and underperformance in both motions).",
      "diagnostic_score": 0.2727272727272727
    },
    {
      "id": "E14",
      "description": "Product-usage telemetry correlation with consulting pipeline qualification: whether specific self-serve usage patterns (feature adoption depth, data volume, team-seat expansion) statistically predict consulting engagement initiation and deal size. Differentiates H8 (telemetry-informed pipeline acceleration) from H11 (unrelated buyer personas) and strengthens or weakens H4 (qualified lead funnel).",
      "diagnostic_score": 0.2727272727272727
    },
    {
      "id": "E15",
      "description": "Incremental engineering and infrastructure cost to operate the PLG tier (hosting, CI/CD, on-call, support tooling, security patching for a second posture) expressed as a ratio to PLG-generated ARR and attributed consulting pipeline value. Differentiates H4 (margin-accretive) from H5 (margin-dilutive distraction) and quantifies the operational burden central to H9 (doubled engineering ops).",
      "diagnostic_score": 0.18181818181818182
    },
    {
      "id": "E16",
      "description": "Observed PLG-to-consulting upsell conversion rate and average time-to-convert: the measured percentage of self-serve PLG accounts that initiate or close a consulting engagement within 12 months, and the median elapsed time. A high rate strongly favors H1/H4/H8; a negligible rate supports H11; a moderate rate with declining consulting ACV supports H6/H10.",
      "diagnostic_score": 0.2727272727272727
    },
    {
      "id": "E17",
      "description": "Firmographic and persona overlap between PLG sign-ups and consulting ICP: analysis of company size, industry, title seniority, and budget authority of PLG adopters versus historical consulting buyers. High overlap differentiates H1/H8 (funnel) from H11 (parallel segments) and H10 (non-ICP audience drain).",
      "diagnostic_score": 0.2727272727272727
    },
    {
      "id": "E18",
      "description": "Consulting win-rate and ACV delta for prospects with prior PLG exposure versus those without: comparative close rates and average deal sizes segmented by whether the prospect used the self-serve tier first. Higher win rates and stable/higher ACV favor H1/H4/H8; lower ACV or longer sales cycles favor H2/H10 (price anchoring and brand dilution).",
      "diagnostic_score": 0.2727272727272727
    },
    {
      "id": "E19",
      "description": "Brand perception and willingness-to-pay data from enterprise buyer research: qualitative or survey-based evidence on how target enterprise decision-makers perceive vendors that offer a free/low-cost self-serve product alongside premium advisory services\u2014whether it signals accessibility and product maturity or cheapens perceived expertise. Directly differentiates H2/H10 from H1/H8.",
      "diagnostic_score": 0.18181818181818182
    },
    {
      "id": "E20",
      "description": "Precedent outcomes from analogous companies operating dual PLG + consulting motions (e.g., Databricks, HashiCorp, Confluent): documented revenue mix trajectories, blended margin trends, internal reorganization events, and whether consulting revenue grew or shrank post-PLG launch. Provides external base-rate evidence that differentiates the optimistic funnel hypotheses (H1/H4/H8) from the operational conflict and dilution hypotheses (H3/H5/H6).",
      "diagnostic_score": 0.18181818181818182
    }
  ],
  "surviving": [
    "H3",
    "H7",
    "H5",
    "H9",
    "H1",
    "H4",
    "H6",
    "H8",
    "H2",
    "H10"
  ],
  "eliminated": [
    "H11"
  ],
  "synthesis": {
    "conclusion": "The ACH analysis most strongly supports H3 (Operationally Incompatible Models) and, in a dead-heat tie, H7 (Shared platform, divergent complexity). Both hypotheses survived the full evidence set with zero inconsistencies, meaning no collected evidence contradicts the proposition that the organizational capabilities, culture, and unit economics required for a scalable PLG product are fundamentally at odds with a consulting practice (H3), and that a shared codebase serving both motions will accumulate crippling tech debt over time (H7). These two hypotheses are complementary rather than contradictory\u2014H3 captures the organizational and economic dimension of the tension while H7 captures its technical manifestation. By contrast, the optimistic funnel-synergy hypotheses (H1, H4, H8) each carry two inconsistencies, meaning at least some evidence actively contradicts the premise that PLG reliably feeds consulting pipeline. The brand-dilution hypotheses (H2, H10) are substantially weakened with five inconsistencies each, and the minimal-crossover hypothesis (H11) was eliminated outright. The core finding is that the evidence collected to date is most consistent with the view that running PLG alongside consulting creates structural operational conflict\u2014not that synergy is impossible, but that the operational friction is the hardest scenario to rule out with the data in hand.",
    "winning_hypothesis_id": "H3",
    "confidence": "Medium",
    "confidence_reasoning": "Confidence is Medium for three reasons. First, H3 and H7 are tied at zero inconsistencies, so we cannot cleanly distinguish a single winner; the conclusion rests on two mutually reinforcing but distinct hypotheses. Second, both H3 and H7 have only 4 consistent evidence items out of 20, with the remaining 16 scored as neutral\u2014meaning the bulk of the evidence collected neither confirms nor disconfirms them, suggesting the evidence base was primarily designed to test funnel-synergy vs. cannibalization questions rather than operational incompatibility. Third, the gap between the top tier (0 inconsistencies) and the next tier (1 inconsistency for H5 and H9) is narrow; a single piece of new disconfirming evidence could collapse the ranking. The conclusion is defensible but not robust to moderate evidence shifts.",
    "key_uncertainties": [
      "Actual measured incremental engineering, support, and infrastructure costs of running both motions simultaneously\u2014if these prove manageable (re-scoring E9), H3 and H7 each lose a key supporting pillar and the funnel-synergy hypotheses become more competitive.",
      "Longitudinal tech-debt accrual data from the shared codebase: whether modular architecture and feature-flag discipline can contain divergence, which would directly weaken H7.",
      "Observed PLG-to-consulting conversion rates and time-to-convert at meaningful sample size (E1, E6, E11)\u2014if conversion rates significantly exceed traditional-channel baselines, H1/H4/H8 would gain consistent evidence and the relative ranking could flip.",
      "Organizational design experiments (e.g., fully separated PLG and consulting teams with independent P&Ls) that could test whether operational incompatibility is inherent or merely a consequence of poor structure, directly challenging H3.",
      "ICP overlap analysis at scale (E3): if a large majority of PLG sign-ups match the consulting ICP, the inconsistency scored against H1/H8 on E3 may warrant re-evaluation, narrowing the gap with H3/H7."
    ],
    "sensitivity_notes": "The five most diagnostic evidence items (E1, E3, E6, E9, E11\u2014each with a diagnosticity score of 0.27) primarily discriminate between the funnel-synergy cluster (H1, H4, H8) and the no-crossover/cannibalization cluster (H6, H10, H11). Of these, E9 (incremental cost and tech-debt burden) is the single piece that simultaneously supports H3 and H7 while being inconsistent with H9 and diagnostic across the board; re-evaluating E9 is the highest-leverage move for shifting the conclusion. E4 (evidence of internal resource conflicts and cultural friction) and E13 (observed codebase complexity or incident cross-contamination) are the other pillars propping up H3 and H7; if either were re-scored from consistent to neutral or inconsistent, the zero-inconsistency advantage disappears. Conversely, the conclusion is relatively insensitive to re-scoring evidence items that are already neutral for H3/H7 (the majority of the matrix). The most fragile aspect of the assessment is that the 'winning' hypotheses are supported by a small number of confirming items and survive primarily because nothing contradicts them\u2014a classic ACH pattern where the least-tested hypothesis wins by default. Obtaining direct, targeted evidence against operational incompatibility (e.g., case studies of firms that successfully run both motions at scale) would be the single most valuable next analytical step."
  },
  "timings": {
    "phase1_generate": 9.147037982940674,
    "phase2_evidence": 25.41325879096985,
    "phase3_matrix": 156.85492086410522,
    "phase4_eliminate": 0.0014531612396240234,
    "phase5_synthesis": 47.14595103263855
  }
}

